def get_artist_name(artist_id, artists):
    for artist in artists:
        if artist['artist_id'] == artist_id:
            return artist['name']
    return ''

# Helper to get album name by id

def get_album_name(album_id, albums):
    for album in albums:
        if album['album_id'] == album_id:
            return album['title']
    return ''

# Helper to get album by id

def get_album(album_id, albums):
    for album in albums:
        if album['album_id'] == album_id:
            return album
    return None

# Helper to get artist by id

def get_artist(artist_id, artists):
    for artist in artists:
        if artist['artist_id'] == artist_id:
            return artist
    return None

# Helper to get song by id

def get_song(song_id, songs):
    for song in songs:
        if song['song_id'] == song_id:
            return song
    return None

# Helper to get playlist by id

def get_playlist(playlist_id, playlists):
    for pl in playlists:
        if pl['playlist_id'] == playlist_id:
            return pl
    return None

# Helper to get next playlist_id

def get_next_playlist_id(playlists):
    max_id = 0
    for pl in playlists:
        if pl['playlist_id'] > max_id:
            max_id = pl['playlist_id']
    return max_id + 1

# Helper to get next playlist_song_id

def get_next_playlist_song_id(playlist_songs):
    max_id = 0
    for pls in playlist_songs:
        if pls['playlist_song_id'] > max_id:
            max_id = pls['playlist_song_id']
    return max_id + 1


