# Load Songs

def load_songs():
    songs = []
    filepath = os.path.join(data_folder, 'songs.txt')
    if not os.path.exists(filepath):
        return songs
    with open(filepath, encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) != 8:
                continue
            try:
                song = {
                    'song_id': int(parts[0]),
                    'title': parts[1],
                    'artist_id': int(parts[2]),
                    'album_id': int(parts[3]),
                    'genre': parts[4],
                    'duration': int(parts[5]),
                    'release_date': parts[6],
                    'play_count': int(parts[7])
                }
                songs.append(song)
            except ValueError:
                continue
    return songs

# Load Artists

def load_artists():
    artists = []
    filepath = os.path.join(data_folder, 'artists.txt')
    if not os.path.exists(filepath):
        return artists
    with open(filepath, encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) != 5:
