                    'genre': parts[2],
                    'country': parts[3],
                    'formation_year': int(parts[4])
                }
                artists.append(artist)
            except ValueError:
                continue
    return artists

# Load Albums

def load_albums():
    albums = []
    filepath = os.path.join(data_folder, 'albums.txt')
