        return playlist_songs
    with open(filepath, encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) != 4:
                continue
            try:
                pls = {
                    'playlist_song_id': int(parts[0]),
                    'playlist_id': int(parts[1]),
                    'song_id': int(parts[2]),
                    'added_date': parts[3]
                }
                playlist_songs.append(pls)
            except ValueError:
                continue
    return playlist_songs

# Save Playlists

def save_playlists(playlists):
    filepath = os.path.join(data_folder, 'playlists.txt')
    with open(filepath, 'w', encoding='utf-8') as f:
        for pl in playlists:
            line = f"{pl['playlist_id']}|{pl['title']}|{pl['description']}|{pl['creation_date']}|{pl['total_songs']}\n"
            f.write(line)

# Save Playlist Songs

def save_playlist_songs(playlist_songs):
    filepath = os.path.join(data_folder, 'playlist_songs.txt')
    with open(filepath, 'w', encoding='utf-8') as f:
        for pls in playlist_songs:
            line = f"{pls['playlist_song_id']}|{pls['playlist_id']}|{pls['song_id']}|{pls['added_date']}\n"
            f.write(line)

# Helper Functions

def get_artist_name(artist_id, artists):
    for artist in artists:
        if artist['artist_id'] == artist_id:
            return artist['name']
    return ''

def get_album_name(album_id, albums):
    for album in albums:
        if album['album_id'] == album_id:
            return album['title']
    return ''

def get_artist(artist_id, artists):
    for artist in artists:
        if artist['artist_id'] == artist_id:
            return artist
    return None

def get_album(album_id, albums):
    for album in albums:
        if album['album_id'] == album_id:
            return album
    return None

def get_song(song_id, songs):
    for song in songs:
        if song['song_id'] == song_id:
            return song
    return None

def get_playlist(playlist_id, playlists):
    for playlist in playlists:
        if playlist['playlist_id'] == playlist_id:
            return playlist
    return None

def get_next_playlist_id(playlists):
    max_id = 0
    for pl in playlists:
        if pl['playlist_id'] > max_id:
            max_id = pl['playlist_id']
    return max_id + 1

