from flask import Flask, render_template, redirect, url_for, request
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Helper functions to load data files

def load_events():
    events = []
    try:
        with open(os.path.join(DATA_DIR, 'events.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                # Assuming events.txt fields delimiter '|'
                # Sample line format (example): event_id|name|description|venue_id|date|category
                parts = line.split('|')
                if len(parts) != 6:
                    continue
                event = {
                    'event_id': parts[0],
                    'name': parts[1],
                    'description': parts[2],
                    'venue_id': parts[3],
                    'date': parts[4],
                    'category': parts[5]
                }
                events.append(event)
    except Exception:
        pass
    return events

def load_venues():
    venues = []
    try:
        with open(os.path.join(DATA_DIR, 'venues.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                # Assuming venues.txt fields delimiter '|'
                # Sample line format (example): venue_id|name|location|capacity
                parts = line.split('|')
                if len(parts) != 4:
                    continue
                venue = {
                    'venue_id': parts[0],
                    'name': parts[1],
                    'location': parts[2],
                    'capacity': parts[3]
                }
                venues.append(venue)
    except Exception:
        pass
    return venues

def load_tickets():
    tickets = []
    try:
        with open(os.path.join(DATA_DIR, 'tickets.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                # Assuming tickets.txt fields delimiter '|'
                # Sample line format (example): ticket_id|event_id|ticket_type|price|available_quantity
                parts = line.split('|')
                if len(parts) != 5:
                    continue
                ticket = {
                    'ticket_id': parts[0],
                    'event_id': parts[1],
                    'ticket_type': parts[2],
                    'price': parts[3],
                    'available_quantity': int(parts[4])
                }
                tickets.append(ticket)
    except Exception:
        pass
    return tickets

def load_bookings():
    bookings = []
    try:
        with open(os.path.join(DATA_DIR, 'bookings.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                # Assuming bookings.txt fields delimiter '|'
                # Sample line format (example): booking_id|user_id|ticket_id|quantity|booking_date
                parts = line.split('|')
