def dashboard():
    events = load_events()
    venues = load_venues()
    # Context variables: events, venues
    return render_template('dashboard.html', events=events, venues=venues)

@app.route('/events')
def events_list():
    events = load_events()
    # Optionally filter by category, date, or search term
    category = request.args.get('category')
    date = request.args.get('date')
    search = request.args.get('search')

    filtered = events
    if category:
        filtered = [e for e in filtered if e['category'].lower() == category.lower()]
    if date:
        filtered = [e for e in filtered if e['date'] == date]
    if search:
        filtered = [e for e in filtered if search.lower() in e['name'].lower() or search.lower() in e['description'].lower()]

    # Context variables: events
    return render_template('events.html', events=filtered)

@app.route('/event/<event_id>')
def event_details(event_id):
    events = load_events()
    venues = load_venues()
    tickets = load_tickets()
    schedules = load_schedules()

    event = next((e for e in events if e['event_id'] == event_id), None)
    if not event:
        return "Event not found", 404

    venue = next((v for v in venues if v['venue_id'] == event['venue_id']), None)
    event_tickets = [t for t in tickets if t['event_id'] == event_id]
    event_schedules = [s for s in schedules if s['event_id'] == event_id]

    # Context variables: event, venue, tickets, schedules
    return render_template('event_details.html', event=event, venue=venue, tickets=event_tickets, schedules=event_schedules)

@app.route('/book_ticket/<ticket_id>', methods=['GET', 'POST'])
def book_ticket(ticket_id):
    tickets = load_tickets()
    bookings = load_bookings()

    ticket = next((t for t in tickets if t['ticket_id'] == ticket_id), None)
    if not ticket:
        return "Ticket type not found", 404

    if request.method == 'POST':
        user_id = request.form.get('user_id')
        quantity = request.form.get('quantity', type=int)
        if not user_id or not quantity or quantity <= 0:
            return "Invalid input", 400
        if ticket['available_quantity'] < quantity:
            return "Not enough tickets available", 400

        # Update bookings
        new_booking_id = str(len(bookings) + 1)  # simplistic new id
        bookings.append({
            'booking_id': new_booking_id,
            'user_id': user_id,
            'ticket_id': ticket_id,
            'quantity': quantity,
            'booking_date': '2024-01-01'  # placeholder, ideally current date
        })

        # Decrease tickets availability
        ticket['available_quantity'] -= quantity

        # Save changes to bookings.txt and tickets.txt
        try:
            with open(os.path.join(DATA_DIR, 'bookings.txt'), 'w', encoding='utf-8') as f:
                for b in bookings:
                    f.write('|'.join([b['booking_id'], b['user_id'], b['ticket_id'], str(b['quantity']), b['booking_date']]) + '\n')
        except Exception:
            pass

        try:
            with open(os.path.join(DATA_DIR, 'tickets.txt'), 'w', encoding='utf-8') as f:
                for t in tickets:
                    f.write('|'.join([t['ticket_id'], t['event_id'], t['ticket_type'], t['price'], str(t['available_quantity'])]) + '\n')
        except Exception:
            pass

        return redirect(url_for('booking_summary'))

    # GET method
    # Context variables: ticket
    return render_template('book_ticket.html', ticket=ticket)

@app.route('/participants')
def participants():
    participants = load_participants()
    # Optionally filter by registered_event_id
    event_id = request.args.get('event_id')
    filtered = participants
    if event_id:
        filtered = [p for p in participants if p['registered_event_id'] == event_id]
    # Context variables: participants
    return render_template('participants.html', participants=filtered)

@app.route('/venues')
def venues_list():
    venues = load_venues()
    # Context variables: venues
    return render_template('venues.html', venues=venues)

@app.route('/schedules')
def schedules_list():
    schedules = load_schedules()
    events = load_events()
    # Context variables: schedules, events
    return render_template('schedules.html', schedules=schedules, events=events)

@app.route('/booking_summary')
def booking_summary():
    bookings = load_bookings()
    tickets = load_tickets()
    events = load_events()

    # Join booking info for display
    detailed_bookings = []
    for b in bookings:
        ticket = next((t for t in tickets if t['ticket_id'] == b['ticket_id']), None)
        event = next((e for e in events if e['event_id'] == ticket['event_id']), None) if ticket else None
        detailed_bookings.append({
            'booking_id': b['booking_id'],
            'user_id': b['user_id'],
            'ticket_id': b['ticket_id'],
            'quantity': b['quantity'],
            'booking_date': b['booking_date'],
            'ticket_type': ticket['ticket_type'] if ticket else None,
            'event_name': event['name'] if event else None
        })

    # Context variables: bookings
    return render_template('booking_summary.html', bookings=detailed_bookings)


if __name__ == '__main__':
    app.run(debug=True, port=5000)

