    return participants

def load_schedules():
    schedules = []
    try:
        with open(os.path.join(DATA_DIR, 'schedules.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                # Assuming schedules.txt fields delimiter '|'
                # Sample line format (example): schedule_id|event_id|session_name|start_time|end_time
                parts = line.split('|')
                if len(parts) != 5:
                    continue
                schedule = {
                    'schedule_id': parts[0],
                    'event_id': parts[1],
                    'session_name': parts[2],
                    'start_time': parts[3],
