# Routes

@app.route('/')
def root():
    return redirect(url_for('dashboard'))

@app.route('/dashboard')
def dashboard():
    events = load_events()
    venues = load_venues()
    # Context variables: events, venues
    return render_template('dashboard.html', events=events, venues=venues)

@app.route('/events')
def events_list():
    events = load_events()
    # Optionally filter by category, date, or search term
    category = request.args.get('category')
    date = request.args.get('date')
    search = request.args.get('search')

    filtered = events
    if category:
        filtered = [e for e in filtered if e['category'].lower() == category.lower()]
    if date:
        filtered = [e for e in filtered if e['date'] == date]
    if search:
        filtered = [e for e in filtered if search.lower() in e['name'].lower() or search.lower() in e['description'].lower()]

    # Context variables: events
    return render_template('events.html', events=filtered)

@app.route('/event/<event_id>')
def event_details(event_id):
    events = load_events()
    venues = load_venues()
    tickets = load_tickets()
    schedules = load_schedules()

    event = next((e for e in events if e['event_id'] == event_id), None)
    if not event:
        return "Event not found", 404

    venue = next((v for v in venues if v['venue_id'] == event['venue_id']), None)
    event_tickets = [t for t in tickets if t['event_id'] == event_id]
    event_schedules = [s for s in schedules if s['event_id'] == event_id]

    # Context variables: event, venue, tickets, schedules
    return render_template('event_details.html', event=event, venue=venue, tickets=event_tickets, schedules=event_schedules)

@app.route('/book_ticket/<ticket_id>', methods=['GET', 'POST'])
def book_ticket(ticket_id):
    tickets = load_tickets()
    bookings = load_bookings()

    ticket = next((t for t in tickets if t['ticket_id'] == ticket_id), None)
    if not ticket:
        return "Ticket type not found", 404

    if request.method == 'POST':
        user_id = request.form.get('user_id')
        quantity = request.form.get('quantity', type=int)
        if not user_id or not quantity or quantity <= 0:
            return "Invalid input", 400
        if ticket['available_quantity'] < quantity:
            return "Not enough tickets available", 400

        # Update bookings
        new_booking_id = str(len(bookings) + 1)  # simplistic new id
        bookings.append({
            'booking_id': new_booking_id,
            'user_id': user_id,
            'ticket_id': ticket_id,
            'quantity': quantity,
            'booking_date': '2024-01-01'  # placeholder, ideally current date
        })

        # Decrease tickets availability
        ticket['available_quantity'] -= quantity

        # Save changes to bookings.txt and tickets.txt
        try:
            with open(os.path.join(DATA_DIR, 'bookings.txt'), 'w', encoding='utf-8') as f:
                for b in bookings:
                    f.write('|'.join([b['booking_id'], b['user_id'], b['ticket_id'], str(b['quantity']), b['booking_date']]) + '\n')
        except Exception:
            pass

        try:
            with open(os.path.join(DATA_DIR, 'tickets.txt'), 'w', encoding='utf-8') as f:
                for t in tickets:
                    f.write('|'.join([t['ticket_id'], t['event_id'], t['ticket_type'], t['price'], str(t['available_quantity'])]) + '\n')
        except Exception:
            pass

        return redirect(url_for('booking_summary'))

    # GET method
    # Context variables: ticket
    return render_template('book_ticket.html', ticket=ticket)

@app.route('/participants')
def participants():
    participants = load_participants()
    # Optionally filter by registered_event_id
    event_id = request.args.get('event_id')
    filtered = participants
    if event_id:
        filtered = [p for p in participants if p['registered_event_id'] == event_id]
    # Context variables: participants
    return render_template('participants.html', participants=filtered)

@app.route('/venues')
def venues_list():
    venues = load_venues()
    # Context variables: venues
    return render_template('venues.html', venues=venues)

@app.route('/schedules')
def schedules_list():
    schedules = load_schedules()
    events = load_events()
    # Context variables: schedules, events
    return render_template('schedules.html', schedules=schedules, events=events)

@app.route('/booking_summary')
def booking_summary():
    bookings = load_bookings()
    tickets = load_tickets()
    events = load_events()

    # Join booking info for display
    detailed_bookings = []
    for b in bookings:
        ticket = next((t for t in tickets if t['ticket_id'] == b['ticket_id']), None)
        event = next((e for e in events if e['event_id'] == ticket['event_id']), None) if ticket else None
        detailed_bookings.append({
            'booking_id': b['booking_id'],
            'user_id': b['user_id'],
            'ticket_id': b['ticket_id'],
            'quantity': b['quantity'],
            'booking_date': b['booking_date'],
            'ticket_type': ticket['ticket_type'] if ticket else None,
            'event_name': event['name'] if event else None
        })

    # Context variables: bookings
    return render_template('booking_summary.html', bookings=detailed_bookings)


if __name__ == '__main__':
    app.run(debug=True, port=5000)

from flask import Flask, render_template, redirect, url_for, request, send_from_directory, flash
import os
import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Helper functions to load and save data

def read_jobs():
    jobs = []
    path = os.path.join(DATA_DIR, 'jobs.txt')
    if not os.path.isfile(path):
        return jobs
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) != 8:
                continue
            job_dict = {
                'job_id': int(parts[0]),
                'title': parts[1],
                'location': parts[2],
                'salary_min': int(parts[3]),
                'salary_max': int(parts[4]),
                'category': parts[5],
                'description': parts[6],
                'posted_date': parts[7],
            }
            jobs.append(job_dict)
    return jobs

def read_companies():
    companies = []
    path = os.path.join(DATA_DIR, 'companies.txt')
    if not os.path.isfile(path):
        return companies
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            # companies.txt fields (5): company_id (int), company_name (str), industry (str), description (str), employee_count (int)
            if len(parts) != 5:
                continue
            try:
                company_dict = {
                    'company_id': int(parts[0]),
                    'company_name': parts[1],
                    'industry': parts[2],
                    'description': parts[3],
                    'employee_count': int(parts[4])
                }
                companies.append(company_dict)
            except Exception:
                continue
    return companies

def read_applications():
    applications = []
    path = os.path.join(DATA_DIR, 'applications.txt')
    if not os.path.isfile(path):
        return applications
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            # applications.txt fields (6): application_id (int), job_id (int), applicant_name (str), applied_date (str), resume_id (int), status (str)
            if len(parts) != 6:
                continue
            try:
                app_dict = {
                    'application_id': int(parts[0]),
                    'job_id': int(parts[1]),
                    'applicant_name': parts[2],
                    'applied_date': parts[3],
                    'resume_id': int(parts[4]),
                    'status': parts[5]
                }
                applications.append(app_dict)
            except Exception:
                continue
    return applications

def read_resumes():
    resumes = []
    path = os.path.join(DATA_DIR, 'resumes.txt')
    if not os.path.isfile(path):
        return resumes
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            # resumes.txt fields (6): resume_id (int), applicant_name (str), applicant_email (str), filename (str), upload_date (str), summary (str)
            if len(parts) != 6:
                continue
            try:
                resume_dict = {
                    'resume_id': int(parts[0]),
                    'applicant_name': parts[1],
                    'applicant_email': parts[2],
                    'filename': parts[3],
                    'upload_date': parts[4],
                    'summary': parts[5]
                }
                resumes.append(resume_dict)
            except Exception:
                continue
    return resumes

def save_applications(applications):
    path = os.path.join(DATA_DIR, 'applications.txt')
    try:
        with open(path, 'w', encoding='utf-8') as f:
            for app in applications:
                line = f"{app['application_id']}|{app['job_id']}|{app['applicant_name']}|{app['applied_date']}|{app['resume_id']}|{app['status']}"
                f.write(line + "\n")
    except Exception:
        pass


@app.route('/')
def root():
    return redirect(url_for('dashboard'))

@app.route('/dashboard')
def dashboard():
    jobs = read_jobs()
    # Compose job list for dashboard with required keys
    # job_id (int), company_name (str), location (str), salary_min (int), salary_max (int)
    # Note: company_name requires mapping from company_id in job? No company_id in jobs.txt? It seems job_id is unique but no company_id in jobs. Based on design spec, jobs.txt probably should have company_name but it is not explicit.
    # Since no direct company_name field in job, treat title as title, location location, salary_min, salary_max, we do not have company_name for jobs since field order is incomplete in spec. We may assume title corresponds to position, company_name unknown.
    # The spec mentions company_name location salary_min salary_max for dashboard jobs but file format in spec for jobs.txt is 8 fields: id,title,location,salary_min,salary_max,category,description,posted_date
    # No company_name in jobs. Unable to do accurate company_name mapping, so set blank or 'Unknown'

    jobs_list = []
    for job in jobs:
        jobs_list.append({
            'job_id': job['job_id'],
            'company_name': 'Unknown',  # company_name not in jobs.txt
            'location': job['location'],
            'salary_min': job['salary_min'],
            'salary_max': job['salary_max'],
        })
    # Generate location list from jobs for filter dropdown
    locations = list(sorted(set(job['location'] for job in jobs)))
    category_filter = ''
    search_query = ''
    title = 'Job Dashboard'

    return render_template('dashboard.html',
                           page_title=title,
                           jobs=jobs_list,
                           locations=locations,
                           location_filter='',
                           category_filter=category_filter,
                           search_query=search_query)

@app.route('/job/<int:job_id>', methods=['GET', 'POST'])
def job_details(job_id):
    jobs = read_jobs()
    job = None
    for j in jobs:
        if j['job_id'] == job_id:
            job = j
            break
    if job is None:
        return "Job not found", 404

    if request.method == 'GET':
        return render_template('job_details.html', job=job)

    # POST - handling application submission
    # form fields: applicant_name (str), resume_file (file), cover_letter (str)
    # Must return context dict: success message (str)

    errors = []
    applicant_name = request.form.get('applicant_name', '').strip()
    cover_letter = request.form.get('cover_letter', '').strip()
    resume_file = request.files.get('resume_file')

    if not applicant_name:
        errors.append('Applicant name is required.')
    if not resume_file or resume_file.filename == '':
        errors.append('Resume file is required.')

    if errors:
        return render_template('application_form.html', job=job, errors=errors)

    # Save uploaded resume file
    resumes = read_resumes()
    # Assign new resume_id
    next_resume_id = (max((r['resume_id'] for r in resumes), default=0)) + 1
    filename = resume_file.filename
    # Save to data/resumes/ directory (must create if not exists)
    resumes_dir = os.path.join(DATA_DIR, 'resumes')
    os.makedirs(resumes_dir, exist_ok=True)
    file_path = os.path.join(resumes_dir, filename)
    resume_file.save(file_path)

    # Resume metadata
    today_str = datetime.datetime.now().strftime('%Y-%m-%d')
    new_resume = {
        'resume_id': next_resume_id,
        'applicant_name': applicant_name,
        'applicant_email': '',  # Not provided in form
        'filename': filename,
        'upload_date': today_str,
        'summary': cover_letter  # store cover_letter here, as no separate field in resume
    }
    resumes.append(new_resume)

    # Save resumes data
    path_resumes = os.path.join(DATA_DIR, 'resumes.txt')
    try:
        with open(path_resumes, 'w', encoding='utf-8') as f:
            for r in resumes:
                line = f"{r['resume_id']}|{r['applicant_name']}|{r['applicant_email']}|{r['filename']}|{r['upload_date']}|{r['summary']}"
                f.write(line+"\n")
    except Exception:
        pass

    # Save application record
    applications = read_applications()
    new_application_id = (max((a['application_id'] for a in applications), default=0)) + 1
    new_application = {
        'application_id': new_application_id,
        'job_id': job_id,
        'applicant_name': applicant_name,
        'applied_date': today_str,
        'resume_id': next_resume_id,
        'status': 'Applied'
    }
    applications.append(new_application)
    save_applications(applications)

    success = 'Application submitted successfully.'
    return render_template('application_form.html', job=job, success=success)

@app.route('/applications')
def application_tracking():
    applications = read_applications()
    # Compose application list for template
    # application_id, company_name (str), applied_date (str), applicant_name (str), resume_id (int), cover_letter(str?)
    # company_name not directly in applications; try mapping via job_id to jobs then company?
    jobs = read_jobs()
    # Build dict job_id -> company_name
    # Company_name unknown due to job data missing company info, so use 'Unknown'
    job_id_to_company_name = {job['job_id']: 'Unknown' for job in jobs}
    app_list = []
    for app in applications:
        app_list.append({
            'application_id': app['application_id'],
            'company_name': job_id_to_company_name.get(app['job_id'], 'Unknown'),
            'applied_date': app['applied_date'],
            'applicant_name': app['applicant_name'],
            'resume_id': app['resume_id'],
            'status': app['status'],
        })

    return render_template('applications.html', applications=app_list, page_title='Applications')

@app.route('/companies')
def companies():
    companies = read_companies()
    search_query = request.args.get('search_query', '').strip()
    filtered_companies = []
    if search_query:
        for comp in companies:
            if search_query.lower() in comp['industry'].lower():
                filtered_companies.append(comp)
    else:
        filtered_companies = companies

    return render_template('companies.html', companies=filtered_companies, search_query=search_query)

@app.route('/resumes', methods=['GET', 'POST'])
def resume_management():
    resumes = read_resumes()

    if request.method == 'GET':
        return render_template('resumes.html', resumes=resumes)

    # POST - handle resume upload
    applicant_name = request.form.get('applicant_name', '').strip()
    applicant_email = request.form.get('applicant_email', '').strip()
    resume_file = request.files.get('resume_file')
    summary = request.form.get('summary', '').strip()

    errors = []
    if not applicant_name:
        errors.append('Applicant name is required.')
    if not applicant_email:
        errors.append('Applicant email is required.')
    if not resume_file or resume_file.filename == '':
        errors.append('Resume file is required.')

    if errors:
        return render_template('resumes.html', resumes=resumes, errors=errors)

    # Save uploaded file
    next_resume_id = (max((r['resume_id'] for r in resumes), default=0)) + 1
    filename = resume_file.filename
    resumes_dir = os.path.join(DATA_DIR, 'resumes')
    os.makedirs(resumes_dir, exist_ok=True)
    file_path = os.path.join(resumes_dir, filename)
    resume_file.save(file_path)

    today_str = datetime.datetime.now().strftime('%Y-%m-%d')

    new_resume = {
        'resume_id': next_resume_id,
        'applicant_name': applicant_name,
        'applicant_email': applicant_email,
        'filename': filename,
        'upload_date': today_str,
        'summary': summary
    }
    resumes.append(new_resume)

    # Save resumes to file
    path_resumes = os.path.join(DATA_DIR, 'resumes.txt')
    try:
        with open(path_resumes, 'w', encoding='utf-8') as f:
            for r in resumes:
                line = f"{r['resume_id']}|{r['applicant_name']}|{r['applicant_email']}|{r['filename']}|{r['upload_date']}|{r['summary']}"
                f.write(line+"\n")
    except Exception:
        pass

    return redirect(url_for('resume_management'))

@app.route('/search')
def search_results():
    search = request.args.get('search', '').strip()
    jobs = read_jobs()
    companies = read_companies()

    # Prepare matching jobs by title, company_name, location
    # company_name not available in jobs, so matching with company_name not possible beyond company data
    # Using jobs' title, location, company_name hardcoded 'Unknown' for filtering to keep spec compliance

    matched_jobs = []
    for job in jobs:
        title_match = search.lower() in job['title'].lower()
        location_match = search.lower() in job['location'].lower()
        # company_name unknown so cannot match
        if search == '' or title_match or location_match:
            matched_jobs.append(job)

    matched_companies = []
    for comp in companies:
        if search.lower() in comp['company_name'].lower():
            matched_companies.append(comp)

    return render_template('search_results.html',
                           search=search,
                           jobs=matched_jobs,
                           company_results=matched_companies)

if __name__ == '__main__':
    app.run(debug=True)

