                continue
            parts = line.split('|')
            # applications.txt fields (6): application_id (int), job_id (int), applicant_name (str), applied_date (str), resume_id (int), status (str)
            if len(parts) != 6:
                continue
            try:
                app_dict = {
                    'application_id': int(parts[0]),
                    'job_id': int(parts[1]),
                    'applicant_name': parts[2],
                    'applied_date': parts[3],
                    'resume_id': int(parts[4]),
                    'status': parts[5]
                }
