def read_resumes():
    resumes = []
    path = os.path.join(DATA_DIR, 'resumes.txt')
    if not os.path.isfile(path):
        return resumes
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            # resumes.txt fields (6): resume_id (int), applicant_name (str), applicant_email (str), filename (str), upload_date (str), summary (str)
            if len(parts) != 6:
                continue
            try:
                resume_dict = {
                    'resume_id': int(parts[0]),
                    'applicant_name': parts[1],
                    'applicant_email': parts[2],
                    'filename': parts[3],
                    'upload_date': parts[4],
                    'summary': parts[5]
                }
                resumes.append(resume_dict)
            except Exception:
                continue
    return resumes

def save_applications(applications):
    path = os.path.join(DATA_DIR, 'applications.txt')
    try:
        with open(path, 'w', encoding='utf-8') as f:
            for app in applications:
                line = f"{app['application_id']}|{app['job_id']}|{app['applicant_name']}|{app['applied_date']}|{app['resume_id']}|{app['status']}"
