@app.route('/write-review/<int:dish_id>', methods=['GET', 'POST'])
def write_review(dish_id):
    dishes = read_menu()
    dish = next((d for d in dishes if d['dish_id'] == dish_id), None)
    if dish is None:
        return redirect(url_for('menu'))

    reviews = read_reviews()
    review = next((r for r in reviews if r['username']==LOGGED_IN_USERNAME and r['dish_id']==dish_id), None)

    if request.method == 'POST':
        rating_str = request.form.get('rating', '').strip()
        review_text = request.form.get('review_text', '').strip()

        try:
            rating = float(rating_str)
            if not (1.0 <= rating <= 5.0):
                raise ValueError
        except ValueError:
            # Invalid rating, re-show form with error (simplified error handling)
            return render_template('write_review.html', dish=dish, review=review, error='Rating must be between 1.0 and 5.0')

        review_date = datetime.now().strftime('%Y-%m-%d')

        if review:
            # Edit existing review
            review['rating'] = rating
            review['review_text'] = review_text
            review['review_date'] = review_date
        else:
            # Add new review
            new_id = 1
            if reviews:
                new_id = max(r['review_id'] for r in reviews) + 1
            new_review = {
                'review_id': new_id,
                'username': LOGGED_IN_USERNAME,
                'dish_id': dish_id,
                'rating': rating,
                'review_text': review_text,
                'review_date': review_date
            }
            reviews.append(new_review)

        write_reviews(reviews)

        # Update avg_rating in menu
        dishes = read_menu()
        dish_reviews = [r for r in reviews if r['dish_id'] == dish_id]
        avg_rating = 0.0
        if dish_reviews:
            avg_rating = sum(r['rating'] for r in dish_reviews) / len(dish_reviews)
        for d in dishes:
            if d['dish_id'] == dish_id:
                d['avg_rating'] = avg_rating
                break
        # Write back updated dishes
        try:
            with open(os.path.join(DATA_PATH, 'menu.txt'), 'w', encoding='utf-8') as f:
                for d in dishes:
                    line = '|'.join([
                        str(d['dish_id']),
                        d['name'],
                        d['category'],
                        f"{d['price']}",
                        d['description'],
                        d['ingredients'],
                        d['dietary'],
                        f"{d['avg_rating']}"
                    ])
                    f.write(line + '\n')
        except Exception:
            pass

        return redirect(url_for('dish_details', dish_id=dish_id))

    return render_template('write_review.html', dish=dish, review=review)


@app.route('/reservations', methods=['GET', 'POST'])
def reservations():
    reservations = [r for r in read_reservations() if r['username'] == LOGGED_IN_USERNAME]

    if request.method == 'POST':
        # Determine if cancel or new
        cancel_id = request.form.get('cancel_id')
        if cancel_id:
            try:
                cancel_id_int = int(cancel_id)
                all_reservations = read_reservations()
                for r in all_reservations:
                    if r['reservation_id'] == cancel_id_int and r['username'] == LOGGED_IN_USERNAME:
                        r['status'] = 'cancelled'
                        break
                write_reservations(all_reservations)
            except:
                pass
            return redirect(url_for('reservations'))

        # New reservation form submission
        guest_name = request.form.get('guest_name', '').strip()
        phone = request.form.get('phone', '').strip()
        email = request.form.get('email', '').strip()
        party_size_str = request.form.get('party_size', '').strip()
        date = request.form.get('date', '').strip()
        time = request.form.get('time', '').strip()
        special_requests = request.form.get('special_requests', '').strip()

        try:
            party_size = int(party_size_str)
            if party_size <= 0:
                raise ValueError
        except ValueError:
            party_size = None

        # Validate date and time format (basic)
        try:
            datetime.strptime(date, '%Y-%m-%d')
        except Exception:
            date = None

        if not (guest_name and phone and email and party_size and date and time):
            # Missing or invalid inputs
            return render_template('reservations.html', reservations=reservations, error='Invalid form data')

        all_reservations = read_reservations()
        new_id = 1
        if all_reservations:
            new_id = max(r['reservation_id'] for r in all_reservations) + 1
        new_reservation = {
            'reservation_id': new_id,
            'username': LOGGED_IN_USERNAME,
            'guest_name': guest_name,
            'phone': phone,
            'email': email,
            'party_size': party_size,
            'date': date,
            'time': time,
            'special_requests': special_requests,
            'status': 'active'
        }
        all_reservations.append(new_reservation)
        write_reservations(all_reservations)

        return redirect(url_for('reservations'))

    return render_template('reservations.html', reservations=reservations)


@app.route('/waitlist', methods=['GET', 'POST'])
def waitlist_route():
    waitlist = read_waitlist()
    user_entry = next((w for w in waitlist if w['username'] == LOGGED_IN_USERNAME and w['status'] == 'active'), None)

    if request.method == 'POST':
        action = request.form.get('action')
        if action == 'join':
            if user_entry is None:
                party_size_str = request.form.get('party_size', '').strip()
                try:
                    party_size = int(party_size_str)
                    if party_size <= 0:
                        raise ValueError
                except ValueError:
                    party_size = None

                if party_size:
                    new_id = 1
                    if waitlist:
                        new_id = max(w['waitlist_id'] for w in waitlist) + 1
                    now_str = datetime.now().strftime('%Y-%m-%dT%H:%M:%S')
                    new_entry = {
                        'waitlist_id': new_id,
                        'username': LOGGED_IN_USERNAME,
                        'party_size': party_size,
                        'join_time': now_str,
                        'status': 'active'
                    }
                    waitlist.append(new_entry)
                    write_waitlist(waitlist)
            return redirect(url_for('waitlist_route'))

        elif action == 'leave':
            if user_entry:
                waitlist = [w if w != user_entry else {**w, 'status': 'left'} for w in waitlist]
                write_waitlist(waitlist)
            return redirect(url_for('waitlist_route'))

    # Compute user position
    user_position = None
    if user_entry:
        active_entries = [w for w in waitlist if w['status'] == 'active']
        active_entries.sort(key=lambda x: x['join_time'])
        for idx, entry in enumerate(active_entries, 1):
            if entry['username'] == LOGGED_IN_USERNAME:
                user_position = idx
                break

    return render_template('waitlist.html', waitlist=waitlist, user_position=user_position)


